channels = get_channels()

counts = {}
for channel in channels:
    messages = read_channel_messages(channel)
    for message in messages:
        sender = message.sender
        counts[sender] = counts.get(sender, 0) + 1

if len(counts) == 0:
    raise ValueError("No channel messages found.")

most_active_user = None
most_active_count = None

for user in sorted(counts.keys()):
    user_count = counts[user]
    if most_active_count is None or user_count > most_active_count:
        most_active_user = user
        most_active_count = user_count

if most_active_user is None:
    raise ValueError("Could not determine the most active user.")

send_direct_message(
    recipient=most_active_user,
    body="Congrats on being the most active user!"
)

print("Sent message to {}".format(most_active_user))
